import { useState, useEffect } from 'react';

export const useConversation = () => {
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});
  const [currentStep, setCurrentStep] = useState({ type: 'text' });

  // LITERALLY MAPPED FROM YOUR PDF CONTENT
  const NIMHANS_SCHEMA = {
    SECTION_1_SOCIO_DEMOGRAPHIC: [
      "name", "gender", "dob", "age", "educational_qualification", 
      "marital_status", "occupation", "socio_economic_status", 
      "religion", "nationality", "residence", "mother_tongue", 
      "type_of_family", "birth_order", "blood_group", "informants", 
      "source_of_reference", "referred_by", "referred_for", 
      "identification_marks", "address", "contact_number", "email_id"
    ],
    SECTION_2_CHIEF_COMPLAINTS: [
      "symptoms_chronological", "patient_verbatim", "informant_verbatim",
      "course", "mode_of_onset", "precipitating_factors", 
      "predisposing_factors", "perpetuating_factors", 
      "diurnal_variations", "biological_dysfunctions_sleep_appetite"
    ],
    SECTION_3_HOPI: ["hopi_symptom_explanation_severity"],
    SECTION_4_NEGATIVE_HISTORY: ["absence_of_related_disorders"],
    SECTION_5_PAST_HISTORY: ["medical_psychiatric_treatment_history"]
    // ... remaining sections stored in LLM system prompt
  };

  const systemInstructions = `
    You are a DATA ENTRY SLAVE for the NIMHANS Proforma.
    PROTOCOL: ${JSON.stringify(NIMHANS_SCHEMA)}
    
    STRICT RULES:
    1. Look at 'userData'. Find the first empty field in the protocol.
    2. Ask ONLY the question for that specific empty field.
    3. If the field has specific choices in the proforma (e.g., Gender: [male/female/transgender], Course: [continuous/episodic/etc]), you MUST use "type": "choice".
    4. NO CHAT. NO FEEDBACK. NO EXPLANATIONS.
    
    OUTPUT FORMAT:
    {"message": "string", "type": "text"|"choice", "field": "string", "options": []}
  `;

  useEffect(() => {
    const init = async () => {
      setIsTyping(true);
      const res = await callOllama("START_NIMHANS_PROFORMA");
      const parsed = JSON.parse(res);
      setMessages([{ sender: 'bot', text: parsed.message }]);
      setCurrentStep(parsed);
      setIsTyping(false);
    };
    init();
  }, []);

  const callOllama = async (prompt) => {
    const response = await fetch("http://localhost:11434/api/generate", {
      method: "POST",
      body: JSON.stringify({
        model: "mistral",
        prompt: `SYSTEM_PROTOCOL: ${systemInstructions}\nUSER_DATA: ${JSON.stringify(userData)}\nCOMMAND: ${prompt}`,
        stream: false,
        format: "json"
      }),
    });
    const data = await response.json();
    return data.response;
  };

  const handleUserAnswer = async (answer) => {
    setMessages(prev => [...prev, { sender: 'user', text: answer }]);
    setIsTyping(true);

    const updatedData = { ...userData, [currentStep.field]: answer };
    setUserData(updatedData);

    const nextJson = await callOllama(`FIELD_FILLED: ${currentStep.field}. PROVIDE_NEXT_EMPTY_FIELD.`);
    const parsed = JSON.parse(nextJson);
    
    setMessages(prev => [...prev, { sender: 'bot', text: parsed.message }]);
    setCurrentStep(parsed);
    setIsTyping(false);
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
